#include <iostream>
#include <cmath>
#include <limits>

class Point2D {
private:
    int x;
    int y;

public:
    Point2D(int valX, int valY) : x(valX), y(valY) {}

    double getDistanceToOrigin() {
        return sqrt(x*x + y*y);
    }
};

int main() {
    Point2D p1(3, 4);
    std::cout << "Distance for (3, 4): " << p1.getDistanceToOrigin() << std::endl;

    Point2D p2(0, 0);
    std::cout << "Distance for (0, 0): " << p2.getDistanceToOrigin() << std::endl;

    Point2D p3(-3, -4);
    std::cout << "Distance for (-3, -4): " << p3.getDistanceToOrigin() << std::endl;

    Point2D p4(50000, 0);
    std::cout << "Distance for (50000, 0): " << p4.getDistanceToOrigin() << std::endl;

    Point2D p5(1, 0);
    std::cout << "Distance for (1, 0): " << p5.getDistanceToOrigin() << std::endl;

    return 0;
}
